const cellKey = ([x, y]: Cell): string => `${x},${y}`;
const parseCellKey = (k: string): Cell => {
  const [x, y] = k.split(",");
  return [Number(x), Number(y)];
};

const countNeighbors = (cells: Cell[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const k = cellKey([x + dx, y + dy]);
      counts.set(k, (counts.get(k) ?? 0) + 1);
    }
  }
  return counts;
};

const survives = (count: number, isLive: boolean): boolean =>
  count === 3 || (count === 2 && isLive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(cellKey));
  const neighborCounts = countNeighbors(cells);

  return [...neighborCounts]
    .filter(([k, count]) => survives(count, live.has(k)))
    .map(([k]) => parseCellKey(k));
}

