const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const countNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = cellKey(cell);
      const entry = counts.get(k);
      if (entry) entry.count++;
      else counts.set(k, { cell, count: 1 });
    }
  }
  return counts;
};

const survives = (count: number, isLive: boolean): boolean =>
  count === 3 || (count === 2 && isLive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(cellKey));

  return [...countNeighbors(cells).entries()]
    .filter(([k, { count }]) => survives(count, live.has(k)))
    .map(([, { cell }]) => cell);
}

